#nullable enable // autogenerated

using MVZ2.GameContent.Effects;
using MVZ2.Vanilla.Level;
using MVZ2.Vanilla.Properties;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Buffs.Level
{
    [AutoBuffDefinition(VanillaBuffNames.Level.lockedChestStage)]
    public class LockedChestStageBuff : BuffDefinition
    {
        public LockedChestStageBuff(string nsp, string name) : base(nsp, name)
        {
        }
        public override void OnCreate(Buff buff)
        {
            base.OnCreate(buff);
            buff.SetProperty(PROP_RNG, buff.Level.CreateRNG());
            buff.SetProperty(PROP_SOUL_TIMER, new FrameTimer(SOUL_INTERVAL));
        }
        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff);
            var timer = buff.GetProperty<FrameTimer>(PROP_SOUL_TIMER);
            if (timer.RunToExpiredAndNotNull())
            {
                timer.Reset();
                SpawnSoul(buff);
            }
        }
        public static void SpawnSoul(Buff buff)
        {
            var rng = buff.GetProperty<RandomGenerator>(PROP_RNG);
            if (rng == null)
            {
                rng = buff.Level.CreateRNG();
                buff.SetProperty(PROP_RNG, rng);
            }
            var y = rng.Next(0, 100f);
            var z = rng.Next(0, 500f);
            var pos = new Vector3(0, y, z);
            buff.Level.Spawn(VanillaEffectID.soulEffect, pos, null)?.Let(e =>
            {
                e.Velocity = Vector3.right * 10;
            });
        }
        public static readonly VanillaBuffPropertyMeta<RandomGenerator> PROP_RNG = new VanillaBuffPropertyMeta<RandomGenerator>("rng");
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_SOUL_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("thunder_timer");
        public const int SOUL_INTERVAL = 4;
    }
}
